const WORKCENTER_ID = 1;

msg.filters = [
    [
        ["state", "in", ["ready", "paused", "progress"]],
        ["workcenter_id", "=", WORKCENTER_ID]
    ]
];

msg.fields = [
    "id",
    "name",
    "production_id",
    "workcenter_id",
    "state",
    "product_id"
];

msg.order = "create_date desc";

msg.limit = 1;
msg.offset = 0;

msg.payload = {}; 

return msg;

const workOrderId = parseInt(msg.payload.workOrderId); 

msg.payload = [workOrderId]; 

msg.method = 'button_start';
msg.args = []; 

return msg;

const workOrderId = parseInt(msg.payload.workOrderId);

msg.payload = [workOrderId];

msg.method = 'button_pending';
msg.args = [];

return msg;

const workOrderId = parseInt(msg.payload.workOrderId);

msg.payload = [workOrderId];

msg.method = 'button_finish';
msg.args = [];

return msg;

if (!msg.payload || msg.payload.length === 0) {
    node.warn("Nenhuma Ordem de Trabalho pendente no Odoo. A aguardar...");
    return null; // Interrompe o fluxo aqui, não envia erro nem lixo para o Arduino!
}

let wo = msg.payload[0];

// O Odoo devolve relações como um array [id, "Nome"]. Vamos extrair o Nome:
let mo_name = wo.production_id ? wo.production_id[1] : "";
let wc_name = wo.workcenter_id ? wo.workcenter_id[1] : "";
let color = wo.product_id ? wo.product_id[1] : "N/A";

msg.payload = {
    metrics: [
        { name: "Command/Type", type: "String", value: "ASSIGN_WORKORDER" },
        { name: "ManufacturingOrder/Id", type: "String", value: mo_name },
        { name: "WorkOrder/Id", type: "String", value: String(wo.id) },
        { name: "ManufacturingOrder/Name", type: "String", value: mo_name },
        { name: "Operation/Name", type: "String", value: wo.name },
        { name: "WorkCenter/Name", type: "String", value: wc_name },
        { name: "Product/Name", type: "String", value: color },
        // KPIs a Zeros para iniciar
        { name: "KPI/Availability", type: "Float", value: 0.0 },
        { name: "KPI/Performance", type: "Float", value: 0.0 },
        { name: "KPI/Quality", type: "Float", value: 0.0 },
        { name: "KPI/OEE", type: "Float", value: 0.0 }
    ],
    timestamp: new Date().getTime()
};

return msg;

let errorMessage = (msg.error && msg.error.message) ? msg.error.message : "";

// Check if the error is the specific Odoo XML-RPC "None" quirk
if (errorMessage === "" || /cannot marshal None/i.test(errorMessage)) {    // FALSE NEGATIVE: The action was successful in Odoo, it just failed the return receipt.
    // treat as a SUCCESS (200).
    msg.payload = {
        metrics: [{ name: "Machine/Ack", type: "String", value: "200" }],
        timestamp: new Date().getTime()
    };

    if (msg.error) {
        delete msg.error;
    }

} else {

    // REAL ERROR: Something actually went wrong.
    // treat as a FAILURE (400)
    msg.payload = {
        metrics: [{ name: "Machine/Ack", type: "String", value: "400" }],
        timestamp: new Date().getTime(),
        errorDetails: errorMessage 
    };  
}

return msg;

const metrics = msg.payload.metrics || [];

function metric(name) {
    const m = metrics.find(x => x.name === name);
    return m ? m.value : "";
}

let eventType = metric("Event/Type");
let workOrderId = metric("WorkOrder/Id");

if (!eventType || !workOrderId) {
    node.warn("Falta Event/Type ou WorkOrder/Id");
    return null;
}

// Normalize
if (eventType === "Start_WorkOrder") eventType = "Start";
if (eventType === "Pause_WorkOrder") eventType = "Pause";
if (eventType === "Stop_WorkOrder") eventType = "Stop";

let currentTimeStamp = Date.now();

// values to store in CrateDB
msg.factoryData = {
    workcenter: "WS1", 
    timestamp: currentTimeStamp,
    eventType: eventType,
    workOrderId: `WO${workOrderId.toString()}`,
    availability: metric("KPI/Availability") ?? 0.0,
    performance: metric("KPI/Performance") ?? 0.0,
    quality: metric("KPI/Quality") ?? 0.0,
    oee: metric("KPI/OEE") ?? 0.0,
    manufacturingOrderId: metric("ManufacturingOrder/Id") || null,
    pauseReason: metric("WorkOrder/PauseReason") || null,
    pauseReasonType: metric("WorkOrder/PauseReasonType") || null
};

// values for odoo
msg.payload = {
    eventType: eventType,
    workOrderId: parseInt(workOrderId),
    manufacturingOrderId: metric("ManufacturingOrder/Id"),
    timestamp: currentTimeStamp,
    pauseReason: metric("WorkOrder/PauseReason"),
    pauseReasonType: metric("WorkOrder/PauseReasonType")
};

// For AAS
msg.opcua = {
    workstation: "WS1",
    state: eventType === "Start" ? "Running" :
           eventType === "Pause" ? "Paused"  :
           eventType === "Stop"  ? "Done"    : "Idle",
    workOrderId:            metric("WorkOrder/Id")?.toString() || "",
    manufacturingOrderId:   metric("ManufacturingOrder/Id") || " ",
    pauseReason:            metric("WorkOrder/PauseReason") || " ",
    pauseReasonType:        metric("WorkOrder/PauseReasonType") || " ",
};

return msg;

const ack = msg.payload?.metrics?.find(
    metric => metric.name === "Machine/Ack"
)?.value;

if (ack !== "200") {
    return null;
}

// prepare crateDB Query
if (msg.factoryData) {
    msg.query = "INSERT INTO factory_events (time, workcenter, event_type, workorder_id, manufacturing_order_id, pause_reason, pause_reason_type) VALUES ($1, $2, $3, $4, $5, $6, $7);";
    msg.params = [
        msg.factoryData.timestamp,
        msg.factoryData.workcenter,
        msg.factoryData.eventType,
        msg.factoryData.workOrderId,
        msg.factoryData.manufacturingOrderId,
        msg.factoryData.pauseReason,
        msg.factoryData.pauseReasonType
    ];
}

return msg;

msg.payload = {
    metrics: [{ name: "Machine/Ack", type: "String", value: "400" }],
    timestamp: new Date().getTime(),
    errorDetails: "test" 
};  

return msg;

const o = msg.opcua;

const props = [
    { item: "WS1.OperationalData.CurrentState", value: o.state },
    { item: "WS1.OperationalData.ActiveWorkOrderId", value: o.workOrderId },
    { item: "WS1.OperationalData.ActiveManufacturingOrderId", value: o.manufacturingOrderId },
    { item: "WS1.OperationalData.PauseReason", value: o.pauseReason },
    { item: "WS1.OperationalData.PauseReasonType", value: o.pauseReasonType },
];

props.forEach(p => {
    node.send({
        payload: {
            messageType: "Variable",
            namespace: "2",
            variableName: p.item,
            variableValue: p.value
        }
    });
});

return null;

const WORKCENTER_ID = 1;



msg._request = {
    workcenter_id: WORKCENTER_ID,
};

msg.filters = [[
    ["id", "=", WORKCENTER_ID]
]];

msg.fields = [
    "id",
    "name",
    "time_start",
    "time_stop"
];

msg.limit = 1;
msg.offset = 0;

return msg;

const rows = Array.isArray(msg.payload) ? msg.payload : [];
const wc = msg.odoo || {};

if (rows.length === 0) {
    node.warn("A query não devolveu Work Orders para o WC 4");
    msg.payload = [];
    return msg;
}

msg.payload = rows.map(r => ({
    ts: new Date().toISOString(),

    workcenter_id: 1,
    workcenter_name: wc.name || null,
    planned_production_time: r.total_elapsed_seconds,
    actual_production_time: r.total_not_value_seconds,
    unit:'ratio',

    availability:
        r.availability == null
            ? null
            : Number(r.availability),

    availability_percent:
        r.availability_percent == null
            ? null
            : Number(r.availability_percent)
}));

msg.payload=msg.payload[0]
msg.topic="availability"
return msg;

const rows = Array.isArray(msg.payload) ? msg.payload : [];
const wc = msg.odoo || {};

msg.performance_rows = rows.map(r => ({
    workcenter_id: 1,
    workcenter_name: wc.name || null,
    total_elapsed_seconds:r.total_elapsed_seconds,
    ideal_cycle_time:r.total_ideal_seconds,
    actual_cycle_time:r.total_not_seconds,
    total_units_produced:r.total_quantity,
    unit: 'ratio',

    performance:
        r.performance == null
            ? null
            : Number(r.performance),

    performance_percent:
        r.performance_percent == null
            ? null
            : Number(r.performance_percent)
}));

msg.payload = msg.performance_rows;
msg.payload = msg.payload[0]
msg.topic="performance"
return msg;

const data = msg.payload;

if (!data.availability || !data.performance || !data.quality) {
    node.warn("Dados incompletos para o cálculo de OEE.");
    return null;
}

const availability = (data.availability.availability_percent || 0) / 100;
const performance = (data.performance.performance_percent || 0) / 100;

const quality = data.quality.quality; 


const oee = availability * performance * quality;

// Preparação da Query
msg.query = `
    INSERT INTO oee_metrics (
        ts, 
        workcenter, 
        availability, 
        performance, 
        quality, 
        oee
    ) VALUES ($1, $2, $3, $4, $5, $6)
`;

msg.params = [
    new Date().toISOString(), 
    "WS1",                       
    availability,            
    performance,              
    quality,                
    oee                     
];

msg.availabilitySubModel={
    value:data.availability.availability,
    unit:"ratio",
    plannedProductionTime:data.availability.planned_production_time,
    actualProductionTime:data.availability.actual_production_time,
    lastUpdated:data.availability.ts
}

msg.performanceSubModel = {
    value: data.performance.performance,
    unit: "ratio",
    idealCycleTime: data.performance.ideal_cycle_time,
    actualCycleTime: data.performance.actual_cycle_time,
    totalUnitsProduced: data.performance.total_units_produced,
    lastUpdated: data.availability.ts
}

msg.qualitySubModel={
    value:data.quality.quality,
    unit:"ratio",
    goodUnits:data.quality.total_quantity,
    defectiveUnits: data.quality.total_defects,
    lastUpdated:data.availability.ts
}


const now = new Date();
const start = new Date(now.getTime() - (24 * 60 * 60 * 1000));

msg.oeeSubModel = {
    value: oee,
    unit: "ratio",
    calculationPeriodStart: start,
    calculationPeriodEnd: now,
    lastUpdated: data.availability.ts
}

return msg;

const WORKCENTER_ID = 1;
msg.payload=null;

msg._request = {
    workcenter_id: WORKCENTER_ID,
};

msg.filters = [[
    ["id", "=", WORKCENTER_ID]
]];

msg.fields = [
    "id",
    "name",
    "time_start",
    "time_stop"
];

msg.limit = 1;
msg.offset = 0;

return msg;

if (!msg.payload || msg.payload.length === 0) {
    node.error("Work Center 4 não encontrado no Odoo", msg);
    return null;
}
msg.wc_data = msg.payload[0];

const OPERATION_ID = 1;

msg.filters = [[
    ["id", "=", OPERATION_ID]
]];

msg.fields = [
    "id",
    "name",
    "time_cycle_manual",
    "workcenter_id"
];

msg.limit = 1;
msg.offset = 0;

return msg;

// ID da Operação no roteiro (mrp.routing.workcenter)
const OPERATION_ID = 1;
msg.payload=null

msg._request = {
    operation_id: OPERATION_ID,
    from: msg.from,
    to: msg.to
};

msg.filters = [[
    ["id", "=", OPERATION_ID]
]];

msg.fields = [
    "id",
    "name",
    "time_cycle_manual",
    "workcenter_id"
];

msg.limit = 1;
msg.offset = 0;

return msg;

const rows = Array.isArray(msg.payload) ? msg.payload : [];

if (rows.length === 0) {
    node.error("Roteiro não encontrado no Odoo", msg);
    return null;
}

const roteiro = rows[0];
const req = msg._request;

const timeCycle = Number(roteiro.time_cycle_manual || 0)*60;

let wcId = 1;
let wcName =  "WS1";

msg.wc_info = { id: wcId, name: wcName };

msg.query = `
WITH wos_in_period AS (
    SELECT DISTINCT
        workorder_id,
        manufacturing_order_id,
        workcenter
    FROM factory_events
    WHERE workcenter = $1
      AND time >= $2::timestamptz
      AND time <  $3::timestamptz
      AND workorder_id IS NOT NULL
      AND event_type != 'Defect_Detected'
),
defects_agg AS (
    SELECT
        manufacturing_order_id,
        SUM(defect_quantity) AS total_defects
    FROM defects
    WHERE workcenter = $5
    GROUP BY manufacturing_order_id
),
calc_per_wo AS (
    SELECT
        w.workcenter,
        1::integer AS produced_quantity,
        COALESCE(d.total_defects, 0)::integer AS defect_quantity
    FROM wos_in_period w
    LEFT JOIN defects_agg d ON w.manufacturing_order_id = d.manufacturing_order_id
)
SELECT
    workcenter,
    SUM(produced_quantity) AS total_quantity,
    SUM(defect_quantity) AS total_defects,
    $4::double precision AS time_cycle,

    ( ($4::double precision * SUM(produced_quantity)) - ($4::double precision * SUM(defect_quantity)) )
      / NULLIF(($4::double precision * SUM(produced_quantity)), 0) AS quality,

    100.0 * ( ($4::double precision * SUM(produced_quantity)) - ($4::double precision * SUM(defect_quantity)) )
      / NULLIF(($4::double precision * SUM(produced_quantity)), 0) AS quality_percent

FROM calc_per_wo
GROUP BY workcenter;
`;


const now = new Date();
const start = new Date(now.getTime() - (24 * 60 * 60 * 1000));

msg.params = [
    "WS1",
    start.toISOString(),
    now.toISOString(),
    timeCycle,
    String(wcId)
];

return msg;

const rows = Array.isArray(msg.payload) ? msg.payload : [];
const wcInfo = msg.wc_info || { id: 1, name: "Desconhecido" };

if (rows.length === 0) {
    msg.payload = [];
    return msg;
}

msg.payload = rows.map(r => ({
    ts: new Date().toISOString(),

    workcenter_id: wcInfo.id,
    workcenter_name: r.workcenter || wcInfo.name,

    total_quantity: Number(r.total_quantity || 0),
    total_defects: Number(r.total_defects || 0),
    time_cycle: Number(r.time_cycle || 0),
    quality: r.quality == null ? null : Number(r.quality),
    quality_percent: r.quality_percent == null ? null : Number(r.quality_percent)
}));

msg.payload = msg.payload[0]
msg.topic = "quality"

return msg;

const a = msg.availabilitySubModel;
const p = msg.performanceSubModel;
const q = msg.qualitySubModel;
const o = msg.oeeSubModel;

const props = [
    // Availability
    { item: "WS1.KPI.Availability.Value",               value: String(a.value) },
    { item: "WS1.KPI.Availability.PlannedProductionTime", value: String(a.plannedProductionTime) },
    { item: "WS1.KPI.Availability.ActualProductionTime",  value: String(a.actualProductionTime) },
    { item: "WS1.KPI.Availability.LastUpdated",           value: String(a.lastUpdated) },
    // Performance
    { item: "WS1.KPI.Performance.Value",                value: String(p.value) },
    { item: "WS1.KPI.Performance.IdealCycleTime",       value: String(p.idealCycleTime) },
    { item: "WS1.KPI.Performance.ActualCycleTime",      value: String(p.actualCycleTime) },
    { item: "WS1.KPI.Performance.TotalUnitsProduced",   value: String(p.totalUnitsProduced) },
    { item: "WS1.KPI.Performance.LastUpdated",          value: String(p.lastUpdated) },
    // Quality
    { item: "WS1.KPI.Quality.Value",                    value: String(q.value) },
    { item: "WS1.KPI.Quality.GoodUnits",                value: String(q.goodUnits) },
    { item: "WS1.KPI.Quality.DefectiveUnits",           value: String(q.defectiveUnits) },
    { item: "WS1.KPI.Quality.LastUpdated",              value: String(q.lastUpdated) },
    // OEE
    { item: "WS1.KPI.OEE.Value",                        value: String(o.value) },
    { item: "WS1.KPI.OEE.CalculationPeriodStart",       value: String(o.calculationPeriodStart) },
    { item: "WS1.KPI.OEE.CalculationPeriodEnd",         value: String(o.calculationPeriodEnd) },
    { item: "WS1.KPI.OEE.LastUpdated",                  value: String(o.lastUpdated) },
];

props.forEach(p => {
    node.send({
        payload: {
            messageType: "Variable",
            namespace: "2",
            variableName: p.item,
            variableValue: p.value
        }
    });
});

return null;

msg.payload = {
    metrics: [{ name: "Machine/Ack", type: "String", value: "200" }],
    timestamp: new Date().getTime(),
    errorDetails: "test" 
};  

return msg;

const WORKCENTER_ID = 2;

msg.filters = [
    [
        ["state", "in", ["ready", "progress"]],
        ["workcenter_id", "=", WORKCENTER_ID]
    ]
];

msg.fields = [
    "id",
    "name",
    "production_id",
    "workcenter_id",
    "state",
    "product_id"
];

msg.order = "create_date desc";

msg.limit = 1;
msg.offset = 0;

msg.payload = {}; 

return msg;

const workOrderId = parseInt(msg.payload.workorder_id_ODOO);

let ultimoEstadoOdoo = flow.get("odoo_current_state");

if (ultimoEstadoOdoo === "START") {
    return null;
}

flow.set("odoo_current_state", "START");

// 4. Prepara o pedido para o Odoo
msg.payload = [workOrderId];
msg.method = 'button_start';
msg.args = [];

return msg;

const workOrderId = parseInt(msg.payload.workorder_id_ODOO);

let ultimoEstadoOdoo = flow.get("odoo_current_state");

if (ultimoEstadoOdoo === "PAUSE") {
    return null;
}

flow.set("odoo_current_state", "PAUSE");

// Prepara o pedido para o Odoo
msg.payload = [workOrderId];
msg.method = 'button_pending';
msg.args = [];

return msg;

const workOrderId = parseInt(msg.payload.workorder_id_ODOO);

msg.payload = [workOrderId];

msg.method = 'button_finish';
msg.args = [];

return msg;

if (!msg.payload || msg.payload.length === 0) {
    node.warn("Nenhuma Ordem de Trabalho pendente no Odoo. A aguardar...");
    return null; // Interrompe o fluxo aqui, não envia erro nem lixo para o Arduino!
}

let wo = msg.payload[0];

// O Odoo devolve relações como um array [id, "Nome"]. Vamos extrair o Nome:
let mo_name = wo.production_id ? wo.production_id[1] : "";
let wc_name = wo.workcenter_id ? wo.workcenter_id[1] : "";
let color = wo.product_id ? wo.product_id[1] : "N/A";
let wo_id   = String(wo.id);

// 1. REGISTO NA MEMÓRIA GLOBAL (A Ponte entre os fluxos)
let odoo_cache = {
    mo_id: mo_name,
    mo_name: mo_name,
    operation_name: wo.name,
    product_name: color,
    workcenter: wc_name
};
let cache_key = "odoo_" + 2 + "_wo_" + wo_id;
global.set(cache_key, odoo_cache);


if (wo.state === "ready") {

    // Verifica qual foi a última Workorder iniciada para evitar SPAM a cada 5 segundos
    let lastSent = flow.get("last_sent_wo");

    if (lastSent !== wo_id) {
        msg.payload = `START,${wo_id}`;
        flow.set("last_sent_wo", wo_id);
        return msg; 
    }
    else {
        return null;
    }
}

return null;

let errorMessage = (msg.error && msg.error.message) ? msg.error.message : "";

// Check if the error is the specific Odoo XML-RPC "None" quirk
if (errorMessage === "" || /cannot marshal None/i.test(errorMessage)) {    // FALSE NEGATIVE: The action was successful in Odoo, it just failed the return receipt.

    // FALSE NEGATIVE: The action was successful in Odoo, it just failed the return receipt.
    // treat as a SUCCESS (200).
    msg.payload = {
        metrics: [{ name: "Machine/Ack", type: "String", value: "200" }],
        timestamp: new Date().getTime()
    };

    delete msg.error;

} else {

    // REAL ERROR: Something actually went wrong.
    // treat as a FAILURE (400)
    msg.payload = {
        metrics: [{ name: "Machine/Ack", type: "String", value: "400" }],
        timestamp: new Date().getTime(),
        errorDetails: errorMessage 
    };

}

return msg;

const sp   = sparkplugPayload.get("spBv1.0");
const tipo = msg.topic.split("/")[2];   // NBIRTH / NDATA / NDEATH

let decoded;
try {
    decoded = sp.decodePayload(msg.payload);
} catch (e) {
    node.warn("decode falhou (" + tipo + "): " + e.message);
    return null;
}

let aliasMap = flow.get("aliasMap") || {};
let estado   = flow.get("estado")   || {};

if (tipo === "NBIRTH") {
    // nascimento: reconstrói mapa e estado de raiz
    aliasMap = {};
    estado   = {};
    decoded.metrics.forEach(m => {
        if (m.alias != null) aliasMap[m.alias] = m.name;
        const nome = m.name || ("alias_" + m.alias);
        estado[nome] = m.value;
    });
    flow.set("aliasMap", aliasMap);
}

// aplica os deltas (no NDATA só vêm as tags que mudaram)
decoded.metrics.forEach(m => {
    const nome = m.name || aliasMap[m.alias] || ("alias_" + m.alias);
    estado[nome] = m.value;
});

flow.set("estado", estado);

msg.payload = Object.assign({}, estado);   // estado COMPLETO a cada mensagem
msg.tipo    = tipo;
return msg;

const p      = msg.payload;
const status = p["Robot/StatusCode"];

// Tabela de estados
const STATUS = {
    0: { event: "IDLE",  reason: "Em espera" },
    1: { event: "START", reason: "Começou o movimento" },
    2: { event: "PAUSE", reason: "A virar para evitar obstáculo" },
    3: { event: "PAUSE", reason: "A desviar de obstáculo" },
    4: { event: "PAUSE", reason: "A procurar a linha" },
    5: { event: "START", reason: "Encontrou a linha" },
    6: { event: "START", reason: "Chegou à workstation" },   
    7: { event: "STOP",  reason: "Paragem" }
};

const info = STATUS[status] || { event: "UNKNOWN", reason: "Estado desconhecido (" + status + ")" };

const ultimo = flow.get("ultimoStatus");
if (status === ultimo) {
    return null;
}
flow.set("ultimoStatus", status);


let raw_wo = p["Robot/WorkorderID"];

let arduino_wo_id = (raw_wo && raw_wo !== 0) 
    ? raw_wo.toString() 
    : flow.get("last_sent_wo") || ""; 

let arduino_wc = 2;
let cache_key = "odoo_" + arduino_wc + "_wo_" + arduino_wo_id;

let odooData = global.get(cache_key) || {
    mo_id: "N/A",
    mo_name: "N/A",
    operation_name: "N/A",
    product_name: "N/A",
    workcenter: "N/A"
};

msg.factoryData = {
    workcenter: "WS2",
    timestamp: Date.now(),
    eventType: info.event,
    workOrderId: `WO${arduino_wo_id}`,
    manufacturingOrderId: odooData.mo_id || null,
    pauseReason: info.reason || null,
    pauseReasonType: "Unplanned"
};

msg.payload = {
    eventType:   info.event,
    reason:      info.reason,
    status_code: status,
    roda1:       p["Robot/Roda1"],
    roda2:       p["Robot/Roda2"],
    obstaculo:   p["Robot/Obstaculo"],
    workstation: `WS${p["Robot/WorkstationCode"]}`,
    workorder_id: `WO${arduino_wo_id}`, // Corrigido aqui
    workorder_id_ODOO: arduino_wo_id,   // Corrigido aqui
    map_request: p["Robot/MapRequest"],
    timestamp:   Date.now()
};

// 3. CORREÇÃO DO OPC-UA (Problema das Maiúsculas/Minúsculas)
msg.opcua = {
    workstation: "WS2",
    state: info.event === "START" ? "Running" :
