      AND time <  $3::timestamptz
      AND workorder_id IS NOT NULL
      AND event_type != 'Defect_Detected'
),
defects_agg AS (
    SELECT
        manufacturing_order_id,
        SUM(defect_quantity) AS total_defects
    FROM defects
    WHERE workcenter = $5
    GROUP BY manufacturing_order_id
),
calc_per_wo AS (
    SELECT
        w.workcenter,
        1::integer AS produced_quantity,
        COALESCE(d.total_defects, 0)::integer AS defect_quantity
    FROM wos_in_period w
    LEFT JOIN defects_agg d ON w.manufacturing_order_id = d.manufacturing_order_id
)
SELECT
    workcenter,
    SUM(produced_quantity) AS total_quantity,
    SUM(defect_quantity) AS total_defects,
    $4::double precision AS time_cycle,

    ( ($4::double precision * SUM(produced_quantity)) - ($4::double precision * SUM(defect_quantity)) )
      / NULLIF(($4::double precision * SUM(produced_quantity)), 0) AS quality,

    100.0 * ( ($4::double precision * SUM(produced_quantity)) - ($4::double precision * SUM(defect_quantity)) )
      / NULLIF(($4::double precision * SUM(produced_quantity)), 0) AS quality_percent

FROM calc_per_wo
